GameListener = {}

function GameListener:init()
    PacketBindEntityEvent.registerCallBack(self.onPacketBindEntity)
    BindChildEntityEvent.registerCallBack(self.onBindChildEntity)
    UnbindChildEntityEvent.registerCallBack(self.onUnbindChildEntity)
    FlyingByPulledCollisionEvent.registerCallBack(self.onFlyingByPulledCollision)
    NeedLogicSpeedUpCheatEvent.registerCallBack(self.onNeedLogicSpeedUpCheat)
    BaseListener.registerCallBack(GameInitEvent, self.onGameInit)
    PacketUserAttrEvent.registerCallBack(self.onPacketUserAttr)
    PacketUnbindEntityEvent.registerCallBack(self.onPacketUnbindEntity)
    WatchAdvertFinishedEvent.registerCallBack(self.onWatchAdvertFinished)
end

function GameListener.onPacketBindEntity(parentEntity, childEntity)
    if not parentEntity or not childEntity then
        return true
    end

    local parent = PlayerManager:getPlayerByEntityId(parentEntity:hashCode())
    if not parent then
        return true
    end

    local child = PlayerManager:getPlayerByEntityId(childEntity:hashCode())
    if child then
        child.property:changeHoldItemActor(0)
        return parent.property.muscleMass * ClientConfig.grabCoe1 >= child.property.muscleMass * ClientConfig.grabCoe2
    end

    local actor = ActorManager:getActor(childEntity:hashCode())
    if actor then
        return BigNum.new(parent.property.muscleMass) >= BigNum.new(string.format("%f", actor:getWeight()))
    end

    return true
end

function GameListener.onBindChildEntity(entityId, childEntityId)
    local playerGrab = PlayerManager:getPlayerByEntityId(entityId)
    if playerGrab == nil then
        return true
    end

    local playerBeGrab = PlayerManager:getPlayerByEntityId(childEntityId)
    if playerBeGrab then
        playerGrab.property.extraMuscle = playerBeGrab.property.muscleMass
    else
        local actor = ActorManager:getActor(childEntityId)
        if actor then
            playerGrab.property.extraMuscle = tonumber(actor.weight)
        end
    end

    if playerGrab:isGrab() then
        --处于抓取状态需要解散队伍
        TeamManager:destroyTeam(playerBeGrab)
    end

    return true
end

function GameListener.onUnbindChildEntity(entityId, childEntityId)
    local playerGrab = PlayerManager:getPlayerByEntityId(entityId)
    if playerGrab == nil then
        return true
    end

    playerGrab.property.extraMuscle = 0

    return true
end

function GameListener.onGameInit(config)
    GameConfig:init(config)
    EngineWorld:stopWorldTime(6000)
    PlayerManager:setMaxPlayer(100)
end

function GameListener.onFlyingByPulledCollision(entityId)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player then
        player:doPulledCollision()
    end
end

function GameListener.onNeedLogicSpeedUpCheat()
    return false
end

function GameListener.onPacketUserAttr(entityPlayer, rakssid)
end

function GameListener.onPacketUnbindEntity(entityId)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if not player then
        return true
    end

    player.property:addInvincibleState()

    return true
end

function GameListener.onWatchAdvertFinished(rakssid, type, params, code)
    print("------------------------------------")
    print("type " .. tostring(type))
    print("params " .. tostring(params))
    print("params " .. tostring(code))
    print("------------------------------------")
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if player == nil then
        return
    end
    if player.curArea ~= Define.Area.ShopArea and player.curArea ~= Define.Area.AutoArea then
        player.property:removeInvincibleState()
    end
    if code ~= 1 then
        return
    end
    if player.isLife == false then
        LuaTimer:schedule(function(player,type, params)
            AdvertConfig:doAdvertReward(player, type, params)
        end,  GameConfig.respawnWaitTime*1000, nil, player,type, tonumber(params))
    else
        AdvertConfig:doAdvertReward(player, type, tonumber(params))
    end
    --AdvertConfig:doAdvertReward(player, type, tonumber(params))
end

return GameListener